<script module lang="ts">
	export interface RFInspectorSidepanelProps {
		classNames?: string;
		title?: string;
		left?: boolean;
		right?: boolean;
		onresize?: (width: number, height: number) => void;
		onclosepanel?: () => void;
		fullscreen?: boolean;
		open?: boolean;
	}
</script>

<script lang="ts">
	import parseBool from '@src/utils/bool';
	import { onMount } from 'svelte';
	import RfInspectorControl from './rf-inspector-control.svelte';

	/**
	 * Props
	 */
	let {
		classNames = '',
		title = '',
		left = true,
		right = false,
		onresize = () => {},
		onclosepanel = () => {},
		open = true,
		fullscreen = false,
	}: RFInspectorSidepanelProps = $props();

	/**
	 * State
	 */
	let isExpanded = $state(open);
	let element: HTMLElement | null = $state(null);

	/**
	 * Derived values
	 */
	const panelClasses = $derived([
		'rf-inspector-sidepanel',
		classNames,
		{
			'rf-inspector-sidepanel--left': parseBool(left),
			'rf-inspector-sidepanel--right': parseBool(right),
			'rf-inspector-sidepanel--expanded': isExpanded,
		},
	]);

	/**
	 * Methods
	 */
	const togglePanel = () => {
		isExpanded = !isExpanded;
		if (!isExpanded) {
			onclosepanel();
		}
	};

	const handleResize = () => {
		if (!element) return;
		const bounds = element.getBoundingClientRect();
		onresize(bounds.width, bounds.height);
	};

	/**
	 * Effects
	 */
	$effect(() => {
		// Handle fullscreen state
		isExpanded = !fullscreen;
	});

	$effect(() => {
		// Sync with external open state
		isExpanded = open;
	});

	/**
	 * Lifecycle
	 */
	onMount(() => {
		if (!element) return;

		// Setup resize observer
		const resizeObserver = new ResizeObserver(handleResize);
		resizeObserver.observe(element);

		// Cleanup on destroy
		return () => {
			resizeObserver.disconnect();
		};
	});
</script>

<div bind:this={element} class={panelClasses}>
	<div class="rf-inspector-sidepanel__controls">
		<span class="rf-inspector-sidepanel__controls__title">{title}</span>

		{#if isExpanded}
			<RfInspectorControl icon="open-panel" onclick={togglePanel} ariaLabel="Retract" />
		{:else if !isExpanded}
			<RfInspectorControl icon="close-panel" onclick={togglePanel} ariaLabel="Expand" />
		{/if}
	</div>

	<div class="rf-inspector-sidepanel__content">
		<slot></slot>
	</div>
</div>

<style lang="scss" global>
	@use 'assets/scss/core/rf-breakpoints' as breakpoint;

	.rf-inspector-sidepanel {
