			top: 0;
			z-index: 10;
			color: white;

			.rf-inspector-sidepanel--right & {
				flex-direction: row-reverse;
			}

			.rf-inspector-sidepanel--expanded & {
				margin-bottom: 8px;
			}

			&__title {
				display: none;
